using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public string DocumentText { get; set; } = string.Empty;

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public string Summary { get; set; } = string.Empty;

    public int OriginalSentenceCount { get; set; }

    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface IDocumentSummarizer
{
    /// <summary>
    /// Produces a concise extractive summary by selecting the most important sentences.
    /// </summary>
    (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(
        string documentText,
        int maxSentences);
}

using System.Text.RegularExpressions;

namespace DocSummary.Services;

public partial class DocumentSummarizer : IDocumentSummarizer
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "as",
        "into", "through", "during", "before", "after", "it", "its",
        "this", "that", "these", "those", "be", "been", "being", "have",
        "has", "had", "do", "does", "did", "will", "would", "shall",
        "should", "may", "might", "must", "can", "could", "not", "no",
        "he", "she", "they", "we", "you", "i", "me", "him", "her", "us",
        "them", "my", "his", "our", "your", "their", "what", "which",
        "who", "whom", "if", "then", "else", "when", "where", "how",
        "all", "each", "every", "both", "few", "more", "most", "other",
        "some", "such", "than", "too", "very", "just", "about", "above",
        "also", "so", "only"
    };

    public (string Summary, int OriginalSentenceCount, int SummarySentenceCount) Summarize(
        string documentText,
        int maxSentences)
    {
        var sentences = SplitIntoSentences(documentText);
        if (sentences.Count == 0)
            return (string.Empty, 0, 0);

        if (sentences.Count <= maxSentences)
            return (string.Join(" ", sentences), sentences.Count, sentences.Count);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scores = ScoreSentences(sentences, wordFrequencies);

        // Pick the top-scoring sentences but preserve their original order.
        var topIndices = scores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summary = string.Join(" ", topIndices.Select(i => sentences[i]));
        return (summary, sentences.Count, topIndices.Count);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceBoundary()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, double> ComputeWordFrequencies(List<string> sentences)
    {
        var freq = new Dictionary<string, double>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (StopWords.Contains(word) || word.Length < 2)
                    continue;

                freq.TryGetValue(word, out var count);
                freq[word] = count + 1;
            }
        }

        // Normalize by the maximum frequency.
        if (freq.Count > 0)
        {
            var max = freq.Values.Max();
            foreach (var key in freq.Keys)
                freq[key] /= max;
        }

        return freq;
    }

    private static double[] ScoreSentences(
        List<string> sentences,
        Dictionary<string, double> wordFrequencies)
    {
        var scores = new double[sentences.Count];

        for (var i = 0; i < sentences.Count; i++)
        {
            var words = Tokenize(sentences[i]);
            if (words.Length == 0)
                continue;

            double total = 0;
            foreach (var word in words)
            {
                if (wordFrequencies.TryGetValue(word, out var f))
                    total += f;
            }

            // Normalize by word count to avoid bias toward longer sentences.
            scores[i] = total / words.Length;

            // Give a slight boost to the first sentence (often the thesis/intro).
            if (i == 0)
                scores[i] *= 1.2;
        }

        return scores;
    }

    private static string[] Tokenize(string sentence)
    {
        return WordPattern()
            .Matches(sentence)
            .Select(m => m.Value.ToLowerInvariant())
            .ToArray();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceBoundary();

    [GeneratedRegex(@"\b[a-zA-Z']+\b", RegexOptions.Compiled)]
    private static partial Regex WordPattern();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly IDocumentSummarizer _summarizer;

    public SummarizeController(IDocumentSummarizer summarizer)
    {
        _summarizer = summarizer;
    }

    /// <summary>
    /// Accepts document text and returns a concise extractive summary.
    /// </summary>
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var (summary, originalCount, summaryCount) = _summarizer.Summarize(
            request.DocumentText,
            request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalSentenceCount = originalCount,
            SummarySentenceCount = summaryCount,
        });
    }
}

